<template>
<div style="margin:45px;height: 80%">
  <div>
    
    <n-space justify="center">
        <n-tag size="large"> 请选择时间区间 </n-tag>
        
        <n-select  v-model:value="data_description" style="width:200px;" :options="data_options" />
        <n-button type="Primary" @click="getSupportPressureData">查询</n-button>
        
    </n-space>
</div>
<div ref="charts" style="margin-left:10%;height:80%;width:80%"></div>
</div>
</template>

<script setup>
import { NDatePicker } from "naive-ui";
import * as echarts from 'echarts';
import 'echarts-gl';
import { onMounted, ref } from 'vue-demi';
import dayjs from "dayjs";
import { getHeatMap } from "@/api/request";
import $ from 'jquery';
//获取时间数据value
let endTime = Date.now();
let startTime = endTime - 24 * 60 * 60 * 1000 ;
const range = ref([startTime, endTime]);
const charts = ref(null);
const heatmapdata = ref(null);
let data_description = ref(1);
let data_options = ref([{"label":"近1天","value":1},{"label":"近2天","value":2}]);
//var ctx = canvas.getContext('2d');

const getSupportPressureData = async () => {
    console.log("触发查询请求")
    let option;
    // start_time: dayjs(range.value[0]).format("YYYY-MM-DD HH:mm:ss"),
    // end_time: dayjs(range.value[1]).format("YYYY-MM-DD HH:mm:ss"),
    let { code, message } = await getHeatMap({
      days:data_description.value
     });
    heatmapdata.value = message;
    console.log("getHeatMap",heatmapdata.value )
    let data = [];
    let chartDom = echarts.init(charts.value)
    data = message
    chartDom.setOption(
    (option = {
      visualMap: {
        show: false,
        min:200,
        max:500,
        inRange: {
          color: [
            '#313695',
            '#4575b4',
            '#74add1',
            '#abd9e9',
            '#e0f3f8',
            '#ffffbf',
            '#fee090',            '#fdae61',
            '#f46d43',
            '#d73027',
            '#a50026'
          ]
        }
      },
      xAxis3D: {
        type: 'value',
        name: "支架号"
      },
      yAxis3D: {
        type: 'value',
        name: "掘进方向"
      },
      zAxis3D: {
        type: 'value',
        name: "支架压力",
        max: 600,
        min: 0
      },
      grid3D: {
        axisLine: {
          lineStyle: { color: '#fff' }
        },
        axisPointer: {
          lineStyle: { color: '#fff' }
        },
        viewControl: {
          // autoRotate: true
        },
        light: {
          main: {
            shadow: true,
            quality: 'ultra',
            intensity: 1.5
          }
        }
      },
      series: [
        {
          type: 'bar3D',
          data: data,
          shading: 'lambert',
          label: {
            formatter: function (param) {
              return param.value[2].toFixed(1);
            }
          }
        }
      ]
    })
  );
    
option && chartDom.setOption(option);
}



</script>